  }

  readonly filterMap: {
    <A, B>(
      f: (a: A) => Option.Option<B>
    ): <R, O, E>(self: Kind<F, R, O, E, A>) => Kind<F, R, O, E, B>
    <R, O, E, A, B>(self: Kind<F, R, O, E, A>, f: (a: A) => Option.Option<B>): Kind<F, R, O, E, B>
  }
}

