          params: { "anthropic-beta": anthropicBeta },
          payload: request
        })
        return { request, stream }
      },
      (effect, options) =>
        effect.pipe(
          Effect.flatMap(({ request, stream }) => makeStreamResponse(request, stream, options)),
          Stream.unwrap,
          Stream.map((response) => {
            annotateStreamResponse(options.span, response)
            return response
          })
        )
    )
  })
