export const layerFromEnv = (
  additionalAttributes?:
    | OtelApi.Attributes
    | undefined
): Layer.Layer<Resource> =>
  Layer.effect(
    Resource,
    Effect.gen(function*() {
      const serviceName = yield* pipe(Config.string("OTEL_SERVICE_NAME"), Config.option, Effect.orDie)
      const attributes = yield* pipe(
        Config.string("OTEL_RESOURCE_ATTRIBUTES"),
        Config.withDefault(""),
        Config.map((s) => {
          const attrs = s.split(",")
          return Arr.reduce(attrs, {} as OtelApi.Attributes, (acc, attr) => {
            const parts = attr.split("=")
            if (parts.length !== 2) {
              return acc
            }
            acc[parts[0].trim()] = parts[1].trim()
            return acc
          })
        }),
        Effect.orDie
      )
      if (serviceName._tag === "Some") {
        attributes[OtelSemConv.ATTR_SERVICE_NAME] = serviceName.value
      }
      if (additionalAttributes) {
        Object.assign(attributes, additionalAttributes)
      }
      return Resources.resourceFromAttributes(attributes)
    })

import type { Subscription} from '@rxjs/observable';
import { Observable, from, operate } from '@rxjs/observable';
import { Subject } from '../Subject.js';
import type { MonoTypeOperatorFunction, ObservableInput } from '../types.js';

export function repeatWhen<T>(notifier: (notifications: Observable<void>) => ObservableInput<any>): MonoTypeOperatorFunction<T> {
  return (source) =>
    new Observable((destination) => {
      let innerSub: Subscription | null;
      let syncResub = false;
      let completions$: Subject<void>;
      let isNotifierComplete = false;
      let isMainComplete = false;

      /**
       * Checks to see if we can complete the result, completes it, and returns `true` if it was completed.
       */
      const checkComplete = () => isMainComplete && isNotifierComplete && (destination.complete(), true);
      /**
       * Gets the subject to send errors through. If it doesn't exist,
       * we know we need to setup the notifier.
       */
      const getCompletionSubject = () => {
        if (!completions$) {
          completions$ = new Subject();

          // If the call to `notifier` throws, it will be caught by the OperatorSubscriber
          // In the main subscription -- in `subscribeForRepeatWhen`.
          from(notifier(completions$)).subscribe(
            operate({
              destination,
              next: () => {
                if (innerSub) {
                  subscribeForRepeatWhen();
                } else {
                  // If we don't have an innerSub yet, that's because the inner subscription
                  // call hasn't even returned yet. We've arrived here synchronously.
                  // So we flag that we want to resub, such that we can ensure finalization
                  // happens before we resubscribe.
                  syncResub = true;
                }
              },
              complete: () => {
                isNotifierComplete = true;
                checkComplete();
              },
            })
          );
        }
        return completions$;
      };

      const subscribeForRepeatWhen = () => {
        isMainComplete = false;

        innerSub = source.subscribe(
          operate({
            destination,
            complete: () => {
              isMainComplete = true;
              // Check to see if we are complete, and complete if so.
              // If we are not complete. Get the subject. This calls the `notifier` function.
              // If that function fails, it will throw and `.next()` will not be reached on this
              // line. The thrown error is caught by the _complete handler in this
              // `OperatorSubscriber` and handled appropriately.
              !checkComplete() && getCompletionSubject().next();
            },
          })
        );

        if (syncResub) {
          // Ensure that the inner subscription is torn down before
          // moving on to the next subscription in the synchronous case.
          // If we don't do this here, all inner subscriptions will not be
          // torn down until the entire observable is done.
          innerSub.unsubscribe();
          // It is important to null this out. Not only to free up memory, but
          // to make sure code above knows we are in a subscribing state to
          // handle synchronous resubscription.
          innerSub = null;
          // We may need to do this multiple times, so reset the flags.
          syncResub = false;
          // Resubscribe
          subscribeForRepeatWhen();
        }
      };

      // Start the subscription
      subscribeForRepeatWhen();
    });
}

import { ArgumentOutOfRangeError } from '../util/ArgumentOutOfRangeError.js';
import { Observable, operate } from '@rxjs/observable';
import type { OperatorFunction } from '../types.js';
import { take } from './take.js';

export function elementAt<T, D = T>(index: number, defaultValue?: D): OperatorFunction<T, T | D> {
  if (index < 0) {
    throw new ArgumentOutOfRangeError();
  }
  const hasDefaultValue = arguments.length >= 2;
  return (source: Observable<T>) =>
    new Observable((destination) => {
      let i = 0;
      const operatorSubscriber = operate<T, T | D>({
        destination,
        next: (value) => {
          if (i++ === index) {
            // We want to unsubscribe from the source as soon as we know
            // we can. This will prevent reentrancy issues if calling
            // `destination.next()` happens to emit another value from source.
            operatorSubscriber.unsubscribe();
            destination.next(value);
            destination.complete();
          }
        },
        complete: () => {
          if (!hasDefaultValue) {
            destination.error(new ArgumentOutOfRangeError());
          } else {
            destination.next(defaultValue!);
            destination.complete();
          }
        },
      });
      source.subscribe(operatorSubscriber);
    });
}

import { Observable, operate } from '@rxjs/observable';
