export function mergeScan<T, R>(
  accumulator: (acc: R, value: T, index: number) => ObservableInput<R>,
  seed: R,
  concurrent = Infinity
): OperatorFunction<T, R> {
  return (source) =>
    new Observable((subscriber) => {
      // The accumulated state.
      let state = seed;

      mergeInternals(
        source,
        subscriber,
        (value, index) => accumulator(state, value, index),
        concurrent,
        (value) => {
          state = value;
