        },
        'user.accept': {
          target: 'startTrivia',
          actions: assign({
            hasLoaded: false
          })
        }
      }
    },
    startTrivia: {
      initial: 'loadQuestionData',
      id: 'startTrivia',
      entry: ['goToTriviaPage', 'resetTriviaData'],
      states: {
        loadQuestionData: {
          id: 'loadQuestionData',
          initial: 'loadCharacter',
          entry: assign({
            hasLoaded: false
          }),
          states: {
            loadCharacter: {
              invoke: {
                src: 'loadSingleCharacter',
                onDone: {
                  actions: assign({
                    currentCharacter: ({ event }) => event.output
                  }),
                  target: 'loadRandomCharacters'
                }
              }
            },
            loadRandomCharacters: {
              invoke: {
                src: 'loadRandomCharacters',
                onDone: {
                  actions: assign({
                    randomCharacters: ({ event }) => event.output,
                    question: ({ context }) => context.question + 1,
                    hasLoaded: true
                  }),
                  target: '#questionReady'
                }
              }
            }
          }
        },
        questionReady: {
          id: 'questionReady',
          initial: 'questionStart',
          on: {
            'user.toggleClue': {
              actions: assign(({ context }) => {
                return {
                  isClueOpened: !context.isClueOpened
                };
              })
            }
          },
          states: {
            questionStart: {
              on: {
                'user.selectAnswer': [
                  {
                    target: 'correctAnswer',
                    guard: 'isAnswerCorrect'
                  },
                  {
                    target: 'incorrectAnswer',
                    guard: not('isAnswerCorrect')
                  }
                ]
              }
            },
            correctAnswer: {
              entry: assign({
                points: ({ context }) => context.points + 10
              }),
              always: [
                {
                  guard: 'hasLostGame',
                  target: 'lostGame'
                },
                {
                  guard: 'hasWonGame',
                  target: 'wonGame'
                }
              ],
              on: {
                'user.nextQuestion': {
                  target: '#loadQuestionData'
                }
              }
            },
            incorrectAnswer: {
              entry: assign({
                lifes: ({ context }) => context.lifes - 1
              }),
              always: [
                {
                  guard: 'hasLostGame',
                  target: 'lostGame'
                },
                {
                  guard: 'hasWonGame',
                  target: 'wonGame'
                }
              ],
              on: {
                'user.nextQuestion': {
                  target: '#loadQuestionData'
                }
              }
            },
            lostGame: {
              on: {
                'user.playAgain': {
                  target: '#startTrivia'
                }
              }
            },
            wonGame: {
              on: {
                'user.playAgain': {
                  target: '#startTrivia'
                }
              }
            }
          }
        }
      }
    }
  }
});

