export function fromCallback<
  TEvent extends EventObject,
  TInput = NonReducibleUnknown,
  TEmitted extends EventObject = EventObject
>(
  callback: CallbackLogicFunction<TEvent, AnyEventObject, TInput, TEmitted>
): CallbackActorLogic<TEvent, TInput, TEmitted> {
  const logic: CallbackActorLogic<TEvent, TInput, TEmitted> = {
    config: callback,
    start: (state, actorScope) => {
      const { self, system, emit } = actorScope;

      const callbackState: CallbackInstanceState<TEvent> = {
        receivers: undefined,
        dispose: undefined
      };

      instanceStates.set(self, callbackState);

      callbackState.dispose = callback({
        input: state.input,
        system,
        self,
        sendBack: (event) => {
          if (self.getSnapshot().status === 'stopped') {
            return;
          }
          if (self._parent) {
            system._relay(self, self._parent, event);
          }
        },
        receive: (listener) => {
          callbackState.receivers ??= new Set();
          callbackState.receivers.add(listener);
        },
        emit
      });
    },
    transition: (state, event, actorScope) => {
      const callbackState: CallbackInstanceState<TEvent> = instanceStates.get(
        actorScope.self
      )!;

      if (event.type === XSTATE_STOP) {
        state = {
          ...state,
          status: 'stopped',
          error: undefined
        };

        instanceStates.delete(actorScope.self);
        callbackState.receivers?.clear();
        callbackState.dispose?.();
        return state;
      }

      callbackState.receivers?.forEach((receiver) => receiver(event));

      return state;
    },
    getInitialSnapshot: (_, input) => {
      return {
        status: 'active',
        output: undefined,
        error: undefined,
        input
      };
    },
    getPersistedSnapshot: (snapshot) => snapshot,
    restoreSnapshot: (snapshot: any) => snapshot
  };

  return logic;
}

import {
  ANY,
  EventStoreDBClient,
  NO_STREAM,
  StreamNotFoundError,
  jsonEvent,
} from '@eventstore/db-client';
import { WrongExpectedVersion } from '@eventstore/db-client/generated/shared_pb';
import { type Event } from './events';

export const getEventStore = (eventStore: EventStoreDBClient): EventStore => {
  return {
    aggregateStream: async <Entity, E extends Event>(
      streamName: string,
      options: {
        evolve: (currentState: Entity, event: E) => Entity;
        getInitialState: () => Entity;
        expectedRevision?: bigint;
      },
    ): Promise<Entity | null> => {
      try {
        const { evolve, getInitialState, expectedRevision } = options;

        let state = getInitialState();
        let streamRevision = -1n;

        for await (const { event } of eventStore.readStream(streamName)) {
          if (!event) continue;

          state = evolve(state, <E>{
            type: event.type,
            data: event.data,
          });
          streamRevision = event.revision;
        }

        if (
          expectedRevision !== undefined &&
          expectedRevision !== streamRevision
        )
          throw new Error(EventStoreErrors.WrongExpectedRevision);

        return state;
      } catch (error) {
        if (error instanceof StreamNotFoundError) {
          return null;
        }

        throw error;
      }
    },
    readStream: async <E extends Event>(streamName: string): Promise<E[]> => {
      const events: E[] = [];

      try {
        for await (const { event } of eventStore.readStream(streamName)) {
          if (!event) continue;
          events.push(<E>{
            type: event.type,
            data: event.data,
          });
        }
        return events;
      } catch (error) {
        if (error instanceof StreamNotFoundError) {
          return [];
        }

        throw error;
      }
    },
    appendToStream: async <E extends Event>(
      streamId: string,
      events: E[],
      options?: { expectedRevision?: bigint },
    ): Promise<bigint> => {
      try {
        const serializedEvents = events.map(jsonEvent);

        const appendResult = await eventStore.appendToStream(
          streamId,
          serializedEvents,
          {
            expectedRevision:
              options?.expectedRevision != undefined
                ? options.expectedRevision !== -1n
                  ? options.expectedRevision
                  : NO_STREAM
                : ANY,
          },
        );

        return appendResult.nextExpectedRevision;
      } catch (error) {
        if (error instanceof WrongExpectedVersion) {
          throw new Error(EventStoreErrors.WrongExpectedRevision);
        }

        throw error;
      }
    },
  };
};

