  evolve: (currentState: State, event: EventType) => State;
  initialState: () => State;
};

import assert from 'assert';

export type CommandHandlerSpecfication<Command, Event> = (
  givenEvents: Event | Event[],
) => {
  when: (command: Command) => {
    then: (expectedEvents: Event | Event[]) => void;
    thenThrows: <Error>(assert: (error: Error) => boolean) => void;
  };
};

export interface CommandBus {
  send<C extends Command>(command: C): Promise<void>;
}

export const CommandBusFactory = (): CommandBus => {
  if (commandBus === undefined) {
    commandBus = {
      send: <C extends Command>(command: C): Promise<void> => {
        const handler = commandHandlers
          .map((handler) => handler(command))
          .find((handler) => handler.canHandle);

        if (handler === undefined || !handler.canHandle) {
          return Promise.reject(
            new Error(
              `Command handler for ${JSON.stringify(command)} not found!`,
            ),
          );
        }
        return handler.handle(command);
      },
    };
  }

  return commandBus;
};

