  setStreamMetadata,
} from '#core/eventStore/appending';
import {
  NO_EVENTS_FOUND,
  readFromStream,
  STREAM_NOT_FOUND,
} from '#core/eventStore/reading';
import { isStreamBatchArchivisationScheduled } from '../schedulingArchivisation/handler';
