  streamName: string,
): Promise<
  Result<
    ReadFromStreamAndSnapshotsResult<StreamEvent | SnapshotStreamEvent>,
    STREAM_NOT_FOUND
  >
> {
  const lastSnapshotVersion = await getLastSnapshotVersionFromStreamMetadata(
    eventStore,
    streamName,
