import {
  ErrorType,
  EventStoreDBClient,
  StreamNotFoundError,
} from '@eventstore/db-client';
import { ReadStreamOptions } from '@eventstore/db-client/dist/streams';
import { STREAM_NOT_FOUND } from '.';
import { Event } from '../../events';
import { failure, Result, success } from '../../primitives';

export async function readFromStream<StreamEvent extends Event>(
  eventStore: EventStoreDBClient,
  streamName: string,
  options?: ReadFromStreamOptions,
): Promise<Result<StreamEvent[], STREAM_NOT_FOUND>> {
  const events = [];

  const toPosition = options?.toPosition;

  try {
    for await (const { event } of eventStore.readStream<StreamEvent>(
      streamName,
      options,
    )) {
      if (!event) continue;

      if (
        toPosition != undefined &&
        (event.position?.commit ?? 0) >= toPosition
      )
        break;

      events.push(<StreamEvent>{
        type: event.type,
        data: event.data,
        metadata: event.metadata,
      });
    }
    return success(events);
  } catch (error) {
    if (error instanceof StreamNotFoundError) {
      return failure('STREAM_NOT_FOUND');
    }

    throw error;
  }
}

import { END, EventStoreDBClient } from '@eventstore/db-client';
import { ReadStreamOptions } from '@eventstore/db-client/dist/streams';
import { Event } from '../../events';
import { readFromStream, STREAM_NOT_FOUND } from '.';
import { failure, Result, success } from '../../primitives';

export async function readLastEventFromStream<StreamEvent extends Event>(
  eventStore: EventStoreDBClient,
  streamName: string,
  options?: ReadStreamOptions,
): Promise<Result<StreamEvent, STREAM_NOT_FOUND | NO_EVENTS_FOUND>> {
  const events = await readFromStream<StreamEvent>(eventStore, streamName, {
    maxCount: 1,
    direction: 'backwards',
    fromRevision: END,
    ...options,
  });

  if (events.isError) {
    return failure('STREAM_NOT_FOUND');
  }

  if (events.value.length === 0) return failure('NO_EVENTS_FOUND');

  return success(events.value[0]);
}

