export async function readSnapshotFromSeparateStream<
  SnapshotStreamEvent extends SnapshotEvent,
>(
  eventStore: EventStoreDBClient,
  streamName: string,
  buildSnapshotStreamName?: (streamName: string) => string,
): Promise<Result<SnapshotStreamEvent, NO_SHAPSHOT_FOUND>> {
  const getSnapshotStreamName = buildSnapshotStreamName || addSnapshotPrefix;
  const snapshotStreamName = getSnapshotStreamName(streamName);

  const result = await readLastEventFromStream<SnapshotStreamEvent>(
    eventStore,
    snapshotStreamName,
  );

  if (result.isError) {
    return failure('NO_SHAPSHOT_FOUND');
  }

  return result;
}

import { EventStoreDBClient } from '@eventstore/db-client';
import {
  NO_SHAPSHOT_FOUND,
  ReadFromStreamAndSnapshotsResult,
  SnapshotEvent,
} from '..';
import { Event } from '../../../events';
import { Result, success } from '../../../primitives';
import {
  readFromStream,
  ReadFromStreamOptions,
  STREAM_NOT_FOUND,
} from '../../reading';

export async function readEventsFromExternalSnapshot<
  StreamEvent extends Event,
  SnapshotStreamEvent extends SnapshotEvent = StreamEvent & SnapshotEvent,
>(
  getLastSnapshot: (
    streamName: string,
  ) => Promise<Result<SnapshotStreamEvent, NO_SHAPSHOT_FOUND>>,
  eventStore: EventStoreDBClient,
  streamName: string,
  readEventsOptions?: ReadFromStreamOptions,
): Promise<
  Result<
    ReadFromStreamAndSnapshotsResult<StreamEvent | SnapshotStreamEvent>,
    STREAM_NOT_FOUND
  >
> {
  const snapshot = await getLastSnapshot(streamName);

  let snapshotEvent: SnapshotStreamEvent | undefined = undefined;
  let lastSnapshotVersion: bigint | undefined = undefined;

  if (snapshot.isError === false) {
    snapshotEvent = snapshot.value;
    lastSnapshotVersion = BigInt(
      snapshotEvent.metadata.snapshottedStreamVersion,
    );
  }

  const events = await readFromStream<StreamEvent>(eventStore, streamName, {
    fromRevision:
      lastSnapshotVersion !== undefined ? lastSnapshotVersion + 1n : undefined,
    ...readEventsOptions,
  });

  if (events.isError == true) {
    return events;
  }

  return success({
    events: snapshotEvent ? [snapshotEvent, ...events.value] : events.value,
    lastSnapshotVersion,
  });
}

import { EventStoreDBClient } from '@eventstore/db-client';
import { ReadFromStreamAndSnapshotsResult, SnapshotEvent } from '..';
import { Event } from '../../../events';
import { Result } from '../../../primitives';
import { ReadFromStreamOptions, STREAM_NOT_FOUND } from '../../reading';
import { readEventsFromExternalSnapshot } from './readEventsFromExternalSnapshot';
import { readSnapshotFromSeparateStream } from './readSnapshotFromSeparateStream';

export async function readEventsFromSnapshotInSeparateStream<
  StreamEvent extends Event,
  SnapshotStreamEvent extends SnapshotEvent = StreamEvent & SnapshotEvent,
>(
  eventStore: EventStoreDBClient,
  streamName: string,
  readEventsOptions?: ReadFromStreamOptions,
  buildSnapshotStreamName?: (streamName: string) => string,
): Promise<
  Result<
    ReadFromStreamAndSnapshotsResult<StreamEvent | SnapshotStreamEvent>,
    STREAM_NOT_FOUND
  >
> {
  return readEventsFromExternalSnapshot<StreamEvent, SnapshotStreamEvent>(
    (streamName) =>
      readSnapshotFromSeparateStream(
        eventStore,
        streamName,
        buildSnapshotStreamName,
      ),
    eventStore,
    streamName,
    readEventsOptions,
  );
}
